using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary (default: 3).
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "above", "below",
        "between", "out", "off", "over", "under", "again", "further",
        "then", "once", "here", "there", "when", "where", "why", "how",
        "all", "both", "each", "few", "more", "most", "other", "some",
        "such", "no", "nor", "not", "only", "own", "same", "so", "than",
        "too", "very", "can", "will", "just", "should", "now", "he", "she",
        "it", "they", "we", "you", "i", "me", "him", "her", "us", "them",
        "my", "your", "his", "its", "our", "their", "this", "that", "these",
        "those", "am", "been", "being", "have", "has", "had", "having",
        "do", "does", "did", "doing", "would", "could", "may", "might",
        "shall", "about", "up", "if", "which", "who", "whom", "what"
    };

    public (string Summary, int OriginalCount, int SummaryCount) Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return (text.Trim(), sentences.Count, sentences.Count);
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scores = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scored sentences, preserving original order.
        var topIndices = scores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .OrderBy(i => i)
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i].Trim()));

        return (summary, sentences.Count, topIndices.Count);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end of string.
        var parts = SentenceSplitRegex().Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();

        return parts;
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in TokenizeWords(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                freq.TryGetValue(word, out int count);
                freq[word] = count + 1;
            }
        }

        if (freq.Count == 0)
            return [];

        double maxFreq = freq.Values.Max();
        return freq.ToDictionary(kv => kv.Key, kv => kv.Value / maxFreq, StringComparer.OrdinalIgnoreCase);
    }

    private static List<double> ScoreSentences(List<string> sentences, Dictionary<string, double> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = TokenizeWords(sentence);
            double score = 0;

            foreach (var word in words)
            {
                if (wordFrequencies.TryGetValue(word, out double freq))
                    score += freq;
            }

            // Normalize by word count to avoid bias toward longer sentences.
            scores.Add(words.Count > 0 ? score / words.Count : 0);
        }

        return scores;
    }

    private static List<string> TokenizeWords(string text)
    {
        return WordTokenRegex().Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitRegex();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordTokenRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer;

    public SummarizeController(DocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = _summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount
        });
    }
}

